{
var seed = GetInt(parameters, "seed", context.Seed);
var scale = GetFloat(parameters, "scale", 4);
var jaggedness = GetFloat(parameters, "jaggedness", 0.5f);
var crystalType = GetChoice(parameters, "crystalType", "single");
var colorA = GetColor(parameters, "colorA", Color.FromRgb(100, 180, 255));
var colorB = GetColor(parameters, "colorB", Color.FromRgb(60, 80, 220));
var colorC = GetColor(parameters, "colorC", Color.FromRgb(180, 100, 255));
var facetLight = GetFloat(parameters, "facetLight", 0.5f);
var edgeGlow = GetFloat(parameters, "edgeGlow", 0.3f);
var refraction = GetFloat(parameters, "refraction", 0.3f);
var opacity = GetFloat(parameters, "opacity", 0.5f);
var brightness = GetFloat(parameters, "brightness", 0f);
var contrast = GetFloat(parameters, "contrast", 0f);
var invert = GetBool(parameters, "invert", false);

var size = context.TileSize;
var buffer = new PixelBuffer(size, size);

var aR = colorA.R / 255f; var aG = colorA.G / 255f; var aB = colorA.B / 255f;
var bR = colorB.R / 255f; var bG = colorB.G / 255f; var bB = colorB.B / 255f;
var cR = colorC.R / 255f; var cG = colorC.G / 255f; var cB = colorC.B / 255f;

// Generate Voronoi points
var cellCount = (int)(scale * 3);
var points = new (float X, float Y, float Hash)[cellCount];
for (var i = 0; i < cellCount; i++)
{
    var px = HashToUnit(i * 7, seed, 111);
    var py = HashToUnit(i * 13, seed * 3, 222);
    var h = HashToUnit(i * 23, seed * 7, 333);
    points[i] = (px, py, h);
}

var period = Math.Max(1, (int)MathF.Round(scale * 2f));

buffer.ParallelForEachPixel((x, y) =>
{
    var u = (x + 0.5f) / size;
    var v = (y + 0.5f) / size;

    // Find nearest Voronoi point
    var minDist = float.MaxValue;
    var minDist2 = float.MaxValue;
    var nearHash = 0f;

    foreach (var (px, py, h) in points)
    {
        // Wrapped distance for tiling
        var dx = MathF.Abs(u - px);
        var dy = MathF.Abs(v - py);
        if (dx > 0.5f) dx = 1f - dx;
        if (dy > 0.5f) dy = 1f - dy;

        var dist = MathF.Sqrt(dx * dx + dy * dy);
        if (dist < minDist)
        {
            minDist2 = minDist;
            minDist = dist;
            nearHash = h;
        }
        else if (dist < minDist2)
        {
            minDist2 = dist;
        }
    }

    // Edge detection
    var edge = (minDist2 - minDist) * scale;

    // Crystal type modifier
    var typeMod = crystalType switch
    {
        "cluster" => TileableFractalNoise(u * 2f, v * 2f, period, 2, 0.5f, 2f, seed + 50),
        "geode" => TileableFractalNoise(u * 1.5f, v * 1.5f, period, 3, 0.55f, 2f, seed + 50),
        _ => 0.5f
    };

    // Facet shading: use hash as pseudo-normal direction
    var facetAngle = nearHash * MathF.PI * 2f + typeMod * 2f;
    var lightAngle = 0.5f;
    var facetShade = 0.5f + MathF.Cos(facetAngle - lightAngle) * facetLight * 0.4f;

    // Crystal interior color with facet variation
    var colorMix = (nearHash + typeMod * 0.3f) % 1f;
    float cRc, cGc, cBc;

    if (colorMix < 0.5f)
    {
        var t = colorMix * 2f;
        cRc = Lerp(aR, bR, t);
        cGc = Lerp(aG, bG, t);
        cBc = Lerp(aB, bB, t);
    }
    else
    {
        var t = (colorMix - 0.5f) * 2f;
        cRc = Lerp(bR, cR, t);
        cGc = Lerp(bG, cG, t);
        cBc = Lerp(bB, cB, t);
    }

    cRc *= facetShade;
    cGc *= facetShade;
    cBc *= facetShade;

    // Prismatic refraction: shift hue based on angle and position
    if (refraction > 0f)
    {
        var prism = MathF.Sin(u * 10f + v * 8f + nearHash * 20f) * refraction * 0.15f;
        cRc += prism;
        cGc += prism * 0.5f;
        cBc -= prism * 0.5f;
    }

    // Edge glow (bright at crystal boundaries)
    var edgeVal = MathF.Max(0f, 1f - edge * 3f);
    var glow = edgeVal * edgeGlow;

    // Jaggedness: modify edge falloff
    var noiseVal = TileableFractalNoise(u * scale * 2f, v * scale * 2f, period, 2, 0.5f, 2f, seed + 100);
    var jitter = (noiseVal - 0.5f) * jaggedness * 0.3f;

    var finalR = cRc + glow + jitter;
    var finalG = cGc + glow * 0.8f + jitter * 0.8f;
    var finalB = cBc + glow * 1.2f + jitter * 0.6f;

    // Transparency / depth effect
    if (opacity < 1f)
    {
        var bgNoise = TileableFractalNoise(u * 3f, v * 3f, period, 1, 0.5f, 2f, seed + 200);
        var bg = bgNoise * 0.3f;
        finalR = Lerp(bg, finalR, opacity);
        finalG = Lerp(bg, finalG, opacity);
        finalB = Lerp(bg + 0.2f, finalB, opacity);
    }

    // Brightness and contrast
    finalR = Math.Clamp(finalR + brightness, 0f, 1f);
    finalG = Math.Clamp(finalG + brightness, 0f, 1f);
    finalB = Math.Clamp(finalB + brightness, 0f, 1f);

    if (MathF.Abs(contrast) > 0.001f)
    {
        var factor = 1f + contrast;
        finalR = (finalR - 0.5f) * factor + 0.5f;
        finalG = (finalG - 0.5f) * factor + 0.5f;
        finalB = (finalB - 0.5f) * factor + 0.5f;
    }

    if (invert) { finalR = 1f - finalR; finalG = 1f - finalG; finalB = 1f - finalB; }

    buffer.SetPixel(x, y,
        Math.Clamp(finalR, 0f, 1f),
        Math.Clamp(finalG, 0f, 1f),
        Math.Clamp(finalB, 0f, 1f), 1f);
});

return buffer;
}
